        hasher.combine(success)
        hasher.combine(raDeg)
        hasher.combine(decDeg)
        hasher.combine(rollDeg)
        hasher.combine(fovDeg)
        hasher.combine(matchedStars)
        hasher.combine(solveTimeMs)
        hasher.combine(rmseArcsec)
